Functions can **return** values instead of just printing:

```javascript
function multiply(a, b) {
  return a * b;
}

let result = multiply(5, 3);
console.log(result);  // Prints: 15
```

When you use `return`, the function stops executing and sends back the value:

```javascript
function checkAge(age) {
  if (age >= 18) {
    return "You are an adult";
  } else {
    return "You are a minor";
  }
}

let message = checkAge(25);
console.log(message);  // Prints: You are an adult
```

blocks.starterCode:
// Function that returns a value
function square(n) {
  return n * n;
}

let result = square(4);
console.log(result);  // 16

// Function with multiple returns
function isEven(num) {
  if (num % 2 === 0) {
    return true;
  } else {
    return false;
  }
}

console.log(isEven(10));  // true
console.log(isEven(7));   // false

// Function that returns a string
function getGrade(score) {
  if (score >= 90) return "A";
  if (score >= 80) return "B";
  if (score >= 70) return "C";
  return "F";
}

console.log(getGrade(85));
